});

frappe.ui.form.on('Opportunity', {
    refresh: function(frm) {
        if (frm.doc.__islocal) { return; }

        // NOTE: add_custom_button dedupes by label, and ERPNext's stock controller
        // already added a 'Quotation' button under 'Create' during this same refresh.
        // So we must REMOVE the stock buttons FIRST and only THEN add our custom ones,
        // otherwise our custom Quotation handler silently fails to bind and the button
        // ends up removed. All adds run inside the same timeout, after the removals.
        setTimeout(function() {
            frm.remove_custom_button('Quotation', 'Create');
            frm.remove_custom_button('Supplier Quotation', 'Create');
            frm.remove_custom_button('Request For Quotation', 'Create');

            frm.add_custom_button(__('Quotation'), function() {
                frappe.call({
                    method: "create_quotation_from_opportunity",
                    args: { opportunity: frm.doc.name },
                    freeze: true,
                    freeze_message: __("Creating Quotation..."),
                    callback: function(r) {
                        var q = r.message && r.message.created_quotation;
                        if (q) {
                            frappe.show_alert({ message: __("Quotation {0} created", [q]), indicator: "green" });
                            frm.reload_doc();
                        }
                    }
                });
            }, __('Create'));

            frm.add_custom_button(__('Finance Dossier'), function() {
                frappe.call({
                    method: "create_finance_dossier_from_opportunity",
                    args: { opportunity: frm.doc.name },
                    freeze: true,
                    freeze_message: __("Creating Finance Dossier..."),
                    callback: function(r) {
                        var fd = r.message && r.message.created_finance_dossier;
                        if (fd) {
                            frappe.show_alert({ message: __("Finance Dossier {0} created", [fd]), indicator: "green" });
                            frm.reload_doc();
                        }
                    }
                });
            }, __('Create'));

            frm.add_custom_button(__('Planning'), function() {
                frappe.new_doc('Planning', {
                    planning_from: "Opportunity",
                    party: frm.doc.name,
                    expected_monthly_volume: frm.doc.custom_expected_monthly_volume,
                    customer_name: frm.doc.title
                });
            }, __('Create'));
        }, 10);
    }
});

// FuelBuddy: Opportunity Value section
//  - custom_rate : excluding-VAT rate from Item Price ("Selling Price List Excluding VAT").
//                  The price list is maintained in the item's STOCK uom (Litre). When the user
//                  switches custom_uom (e.g. Litre <-> IG) the rate is reconverted using the SAME
//                  method Sales Order Item uses: erpnext.stock.get_item_details.get_conversion_factor.
//                      rate(uom) = base_stock_rate * conversion_factor(uom)
//  - custom_expected_monthly_volume : reconverted INVERSELY on a UOM switch so the physical
//                  quantity (qty_stock = qty * conversion_factor, like SO Item's stock_qty) is
//                  preserved, keeping opportunity_amount = volume * rate INVARIANT across Litre<->IG.
//  - custom_uom  : defaults to Litre, filtered to the selected product's UOMs.
//  - opportunity_amount = custom_expected_monthly_volume * custom_rate
//
// Design notes (see review findings):
//  * On opening a SAVED doc we NEVER re-pull the price list; instead we back-compute the cached
//    base (stock-uom) rate from the saved rate, so a later UOM toggle reconverts the SAVED rate
//    (preserving manual overrides) rather than clobbering it.
//  * _prev_uom (the uom the current rate/volume values are expressed in) is advanced ONLY after a
//    conversion successfully completes, so a failed get_conversion_factor cannot corrupt the next toggle.
frappe.ui.form.on("Opportunity", {
    onload: function (frm) {
        apply_uom_query(frm);
        load_item_uoms(frm);
        if (frm.is_new()) {
            if (!frm.doc.custom_uom) {
                frm.set_value("custom_uom", "Litre");   // ok to trigger on a brand-new doc
            }
        } else if (!frm.doc.custom_uom && frm.doc.custom_product) {
            // legacy saved doc with empty uom: set WITHOUT firing the change handler so the
            // saved custom_rate / volume are not clobbered merely by opening the document.
            frm.doc.custom_uom = "Litre";
            frm.refresh_field("custom_uom");
        }
        frm._prev_uom = frm.doc.custom_uom;   // baseline for volume conversion
    },
    refresh: function (frm) {
        apply_uom_query(frm);
        frm._prev_uom = frm.doc.custom_uom;   // re-baseline after save / reload
        seed_base_rate_from_saved(frm, frm.doc.custom_uom, flt(frm.doc.custom_rate));
    },
    custom_product: function (frm) {
        // new product -> reset the cached base rate and (re)fetch it
        frm._base_rate = undefined;
        load_item_uoms(frm, function () {
            apply_uom_query(frm);
            var allowed = frm._allowed_uoms || [];
            if (frm.doc.custom_uom && allowed.indexOf(frm.doc.custom_uom) === -1) {
                // the previously-selected uom is not valid for the new product. set_query only
                // filters the dropdown, it does not clear an already-set value, so reset it to the
                // new item's stock uom before fetching/converting the rate.
                frappe.db.get_value("Item", frm.doc.custom_product, "stock_uom").then(function (res) {
                    var stock_uom = res && res.message && res.message.stock_uom;
                    if (!stock_uom) { fetch_ex_vat_rate(frm); return; }
                    frm._prev_uom = stock_uom;                 // advance tracker before the forced set
                    frm.set_value("custom_uom", stock_uom);    // old===new in the handler -> no volume convert
                    fetch_ex_vat_rate(frm);
                });
            } else {
                fetch_ex_vat_rate(frm);
            }
        });
    },
    custom_uom: function (frm) {
        var old_uom = frm._prev_uom;
        var new_uom = frm.doc.custom_uom;
        // reconvert rate AND volume from one consistent snapshot; advances _prev_uom on success.
        reconvert_for_uom(frm, old_uom, new_uom);
    },
    custom_rate: function (frm) {
        calc_opportunity_amount(frm);
    },
    custom_expected_monthly_volume: function (frm) {
        calc_opportunity_amount(frm);
    }
});

function apply_uom_query(frm) {
    frm.set_query("custom_uom", function () {
        var uoms = frm._allowed_uoms || [];
        if (frm.doc.custom_product && uoms.length) {
            return { filters: [["UOM", "name", "in", uoms]] };
        }
        return {};
    });
}

function load_item_uoms(frm, cb) {
    if (!frm.doc.custom_product) {
        frm._allowed_uoms = [];
        if (cb) { cb(); }
        return;
    }
    frappe.call({
        method: "frappe.client.get",
        args: { doctype: "Item", name: frm.doc.custom_product },
        callback: function (r) {
            if (r.message) {
                frm._allowed_uoms = (r.message.uoms || []).map(function (u) { return u.uom; });
            } else {
                frm._allowed_uoms = [];
            }
            if (cb) { cb(); }
        }
    });
}

// Sales Order Item method: fetch the conversion factor (stock-uom units per 1 of `uom`) for the
// given item + uom, then hand it to `cb`. On failure the error is surfaced and `cb` is NOT called,
// so callers neither fabricate a wrong value nor advance state on an incomplete conversion.
function get_conversion_factor(frm, uom, cb) {
    if (!frm.doc.custom_product || !uom) { return; }
    frappe.call({
        method: "erpnext.stock.get_item_details.get_conversion_factor",
        args: { item_code: frm.doc.custom_product, uom: uom },
        callback: function (r) {
            if (r && r.message && !r.exc) {
                cb(flt(r.message.conversion_factor) || 1);
            } else {
                frappe.show_alert({
                    message: __("Could not fetch the UOM conversion factor for {0}.", [uom]),
                    indicator: "red"
                });
            }
        }
    });
}

// On opening a SAVED doc, derive the cached stock-uom base rate from the persisted custom_rate so a
// later UOM toggle reconverts the SAVED rate (preserving any manual override and keeping
// opportunity_amount invariant). Does NOT touch custom_rate and never re-reads the price list.
// saved_uom / saved_rate are captured at refresh time so a toggle mid-seed cannot corrupt the base.
function seed_base_rate_from_saved(frm, saved_uom, saved_rate) {
    if (frm._base_rate !== undefined) { return; }   // already known this session
    if (frm.is_new()) { return; }                   // unsaved -> the product change path fetches it
    if (!frm.doc.custom_product || !saved_uom) { return; }
    if (!saved_rate) { return; }                    // nothing to back-compute from
    get_conversion_factor(frm, saved_uom, function (cf) {
        if (!cf) { return; }
        frm._base_rate = saved_rate / cf;           // base per stock uom; no set_value -> rate untouched
        // if the user toggled the uom while we were seeding, reconvert from the saved uom now.
        if (frm.doc.custom_uom !== saved_uom) {
            reconvert_for_uom(frm, saved_uom, frm.doc.custom_uom);
        }
    });
}

// Fetch the ex-VAT base rate for the item in its STOCK uom (the UOM the price list is maintained in),
// cache it on the form, then convert to the selected UOM. Only ever called on a product change.
function fetch_ex_vat_rate(frm) {
    if (!frm.doc.custom_product) { return; }
    frappe.db.get_value("Item", frm.doc.custom_product, "stock_uom").then(function (res) {
        var stock_uom = res && res.message && res.message.stock_uom;
        if (!stock_uom) { return; }
        frappe.db.get_list("Item Price", {
            filters: {
                item_code: frm.doc.custom_product,
                price_list: "Selling Price List Excluding VAT",
                uom: stock_uom
            },
            fields: ["price_list_rate"],
            order_by: "creation desc",
            limit: 1
        }).then(function (rows) {
            if (rows && rows.length) {
                frm._base_rate = rows[0].price_list_rate;   // per stock uom (e.g. per Litre)
                apply_rate_for_uom(frm);
            } else {
                frm._base_rate = null;                      // attempted, none found
                frm.set_value("custom_rate", 0);            // clear the previous product's stale rate
                frappe.show_alert({
                    message: __("No 'Selling Price List Excluding VAT' price found for this product."),
                    indicator: "orange"
                });
            }
        });
    });
}

// Set custom_rate for the currently-selected uom from the cached stock-uom base rate.
// Used after a product-change fetch; does NOT re-pull the price list on a uom toggle.
function apply_rate_for_uom(frm) {
    if (!frm.doc.custom_product || !frm.doc.custom_uom) { return; }
    if (frm._base_rate === undefined || frm._base_rate === null) { return; }
    get_conversion_factor(frm, frm.doc.custom_uom, function (cf) {
        if (!cf) { return; }
        frm.set_value("custom_rate", flt(frm._base_rate) * cf);
    });
}

// Reconvert rate and volume together when the UOM changes:
//   rate     = base_stock_rate * cf(new_uom)
//   vol_new  = vol_old * cf(old_uom) / cf(new_uom)   (preserves the physical quantity)
// so opportunity_amount = vol_new * rate stays invariant. _prev_uom is advanced only once the
// conversion has actually been applied, so a failed conversion cannot corrupt a later toggle.
function reconvert_for_uom(frm, old_uom, new_uom) {
    if (!frm.doc.custom_product || !new_uom) { return; }
    if (frm._base_rate === undefined || frm._base_rate === null) { return; }
    var vol = flt(frm.doc.custom_expected_monthly_volume);
    get_conversion_factor(frm, new_uom, function (cf_new) {
        if (!cf_new) { return; }
        var rate = flt(frm._base_rate) * cf_new;
        if (old_uom && old_uom !== new_uom && vol) {
            get_conversion_factor(frm, old_uom, function (cf_old) {
                if (!cf_old) { return; }
                frm.set_value("custom_rate", rate);
                frm.set_value("custom_expected_monthly_volume", vol * cf_old / cf_new);
                frm._prev_uom = new_uom;
            });
        } else {
            frm.set_value("custom_rate", rate);
            frm._prev_uom = new_uom;
        }
    });
}

function calc_opportunity_amount(frm) {
    var amount = (frm.doc.custom_expected_monthly_volume || 0) * (frm.doc.custom_rate || 0);
    frm.set_value("opportunity_amount", amount);
    frm.set_value("base_opportunity_amount", amount * (frm.doc.conversion_rate || 1));
}

frappe.ui.form.on("Opportunity", {
    onload: function(frm) {
        toggle_discount_fields(frm);
    },
    refresh: function(frm) {
        toggle_discount_fields(frm);
    },
    custom_discount_method: function(frm) {
        toggle_discount_fields(frm);
    },
    custom_percentageper_litre: function(frm) {
        toggle_discount_fields(frm);
    }
});

function toggle_discount_fields(frm) {
    if (frm.doc.custom_discount_method === "Slab Discount") {
        frm.set_df_property("custom_percentageper_litre", "hidden", 1);
        frm.set_df_property("custom_percentage_value", "hidden", 1);
        frm.set_df_property("custom_per_litre_value", "hidden", 1);
        frm.set_df_property("custom_max_discount_value", "hidden", 1);
        frm.set_df_property("custom_slab_discount", "hidden", 0);
    } else if (frm.doc.custom_discount_method === "Non-Slab Discount") {
        frm.set_df_property("custom_percentageper_litre", "hidden", 0);
        if (frm.doc.custom_percentageper_litre === "Percentage") {
            frm.set_df_property("custom_percentage_value", "hidden", 0);
            frm.set_df_property("custom_per_litre_value", "hidden", 1);
            frm.set_df_property("custom_slab_discount", "hidden", 1);
        } else if (frm.doc.custom_percentageper_litre === "Per Litre") {
            frm.set_df_property("custom_percentage_value", "hidden", 1);
            frm.set_df_property("custom_per_litre_value", "hidden", 0);
            frm.set_df_property("custom_slab_discount", "hidden", 1);
        } else {
            frm.set_df_property("custom_percentage_value", "hidden", 1);
            frm.set_df_property("custom_per_litre_value", "hidden", 1);
            frm.set_df_property("custom_slab_discount", "hidden", 1);
        }
    } else {
        frm.set_df_property("custom_percentageper_litre", "hidden", 0);
        frm.set_df_property("custom_percentage_value", "hidden", 0);
        frm.set_df_property("custom_per_litre_value", "hidden", 0);
        frm.set_df_property("custom_max_discount_value", "hidden", 0);
        frm.set_df_property("custom_slab_discount", "hidden", 0);
    }
}

frappe.ui.form.on('Opportunity', {
    onload: function(frm) {
        frm.set_query('custom_customer_billing_address', function() {
            return {
                filters: [
                    ['Dynamic Link', 'link_doctype', '=', frm.doc.opportunity_from],
                    ['Dynamic Link', 'link_name', '=', frm.doc.party_name],
                    ['Address', 'address_type', '=', 'Billing']
                ]
            };
        });
    }
});

frappe.ui.form.on('Opportunity', {
    refresh: function(frm) {
        if (!frm.doc.__islocal) {
            frm.add_custom_button(__('Address'), function () {
                frappe.model.with_doctype('Address', function() {
                    let new_address = frappe.model.get_new_doc('Address');

                    new_address.links = [];

                    new_address.links.push({
                        link_doctype: frm.doctype,
                        link_name: frm.doc.name
                    });

                    new_address.custom_opportunity = frm.doc.name;

                    frappe.set_route('Form', 'Address', new_address.name);
                });
            }, __('Create'));
        }
    }
});

frappe.ui.form.on('Opportunity', {
    custom_product: function(frm) {
        if (frm.doc.parent_item) {
            // Check if item already exists in the table
            let exists = frm.doc.items.some(row => row.item_code === frm.doc.custom_product);
            if (!exists) {
                // Append new row to the child table
                let row = frm.add_child('items', {
                    item_code: frm.doc.custom_product,
                    qty: 1
                });
                frm.refresh_field('items');
            }
        }
    }
});

frappe.ui.form.on('Opportunity', {
    validate: function (frm) {
        (frm.doc.custom_opportunity_hse || []).forEach((row, index) => {
            const row_label = `Row ${index + 1} - ${row.address || ''}`;

            if (row.custom_hse_check === 0 && !row.reason_for_rejection) {
                frappe.throw(`${row_label}: Reason for rejection is required when HSE Check is not ticked.`);
            }

            if (row.custom_hse_check === 1 && row.reason_for_rejection) {
                frappe.throw(`${row_label}: Reason for rejection must be empty if HSE Check is ticked.`);
            }
        });
    }
});

// https://coda.io/d/FuelBuddy-UAE_d0o9jYTjb2f/Opportunity-Category_suUGqjZb#_luFN2ttB
frappe.ui.form.on('Opportunity', {
	qty:function(frm) {
