		    frm.set_value("category","Bronze");
		} else if (frm.doc.qty == "149000") {
		    frm.set_value("category","Silver");
		} else if (frm.doc.qty == "249000") {
		    frm.set_value("category","Gold");
		} else {
		    frm.set_value("category","Platinum");
		}
	},
});

// Calculating Opportunity Amount
frappe.ui.form.on('Opportunity', {
    rate:function(frm) {
        frm.set_value("opportunity_amount" , (frm.doc.qty * frm.doc.rate))

    }
});

frappe.ui.form.on('Opportunity', {
	party_name:function(frm) {
		if (frm.doc.opportunity_from == "Lead"){
		    frm.set_value("sales_stage","In Discussion Meeting Pending");
		}
		else if (frm.doc.opportunity_from == "Customer"){
		    frm.set_value("sales_stage","In Discussion Meeting Pending");
		}
	},
});




frappe.ui.form.on('Opportunity', {

	activity_:function(frm) {

		const activity_ = frm.doc.activity_;

		switch (activity_) {
			case "1.In Discussion Meeting Pending": 
				frm.set_value("sales_stage","In Discussion Meeting Pending");
		    	frm.set_value("status","Open");

			case "2.Meeting Scheduled": 
				frm.set_value("sales_stage","Meeting Scheduled");

			case "3.In Negotitation": 
				frm.set_value("sales_stage","In Negotitation");

			case "4.Finance Approval Pending": 
				frm.set_value("sales_stage","Finance Approval Pending");
		    	frm.set_value("status","Replied");

			case "6.Ops Approval Pending": 
				frm.set_value("sales_stage","Ops Approval Pending");
		    	frm.set_value("status","Replied");

			case "7.Ops approved- Finance closure Pending":
				frm.set_value("sales_stage","Ops approved- Finance closure Pending");
		    	frm.set_value("status","Replied");

			case "8.Lost": 
				frm.set_value("sales_stage","Lost");
		    	frm.set_value("status","Lost");

			case "9.On-boarded":
				frm.set_value("sales_stage","On-boarded");

		}

	},
});



frappe.ui.form.on('Opportunity', {
	status:function(frm) {
	    if (frm.doc.status == "Quotation"){
