		}
	},
});


frappe.ui.form.on('Opportunity', {
	workflow_state_of_planning:function(frm) {
		if (frm.doc.workflow_state_of_planning == "Approved"){
		    frm.set_value("sales_stage","Ops approved- Finance closure Pending");
		    frm.set_value("activity_","7.Ops approved- Finance closure Pending");
		    frm.set_value("status","Replied");
		}
	},
});


frappe.ui.form.on('Opportunity', {
