function update_discount_line(frm) {

    if (!frm.doc.name || !frm.doc.items.length) {
        return;
    }

    const total_qty = frm.doc.items
        .filter(row => !row.custom_is_discount)
        .reduce((sum, row) => sum + (parseFloat(row.qty) || 0), 0);

    console.log("✅ Total quantity (excluding discount lines):", total_qty);

    const lead_name = frm.doc.party_name;
    if (!lead_name) {
        return;
    }
    if (total_qty === 0) {
        return;
    }


    frappe.call({
        method: "get_addresses_linked_to_lead",
        args: {
            lead_name: lead_name
        },
        callback: function(r) {
            console.log("ℹ️ Address fetch response:", r);

            if (!r.message || r.message.length === 0) {
                return;
            }

            const address_doc = r.message[0];
            const address = address_doc.name;

            calculate_discount_with_address(frm, address, total_qty);
        }
    });
}

function calculate_discount_with_address(frm, address, total_qty) {
    frappe.call({
        method: 'frappe.client.insert',
        args: {
            doc: {
                doctype: 'Discount Calculation',
                quotation: frm.doc.name || "",
                opportunity: frm.doc.custom_opportunity_from || frm.doc.opportunity || "",
                quantity: total_qty,
                address: address
            }
        },
        callback: function(r) {

            if (!r.message || !r.message.discount) {
                return;
            }

            const discount = r.message.discount;

            frm.doc.items = frm.doc.items.filter(row => !row.custom_is_discount);

            if (discount > 0) {
                frm.add_child('items', {
                    item_name: 'Discount',
                    item_code: 'Discount',
                    qty: 1,
                    rate: -discount,
                    custom_is_discount: 1,
                    delivery_date: frm.doc.delivery_date,
                    uom: 'Litre'
                });
            } else {
                console.log("Discount value <= 0. No line item added.");
            }

            frm.refresh_field('items');
        }
    });
}

