frappe.ui.form.on("Lead", {
    refresh(frm) {
        // Ensure we're not interfering with new or customer-converted leads
        if (frm.is_new() || (frm.doc.__onload && frm.doc.__onload.is_customer)) return;

        // Remove default Opportunity button
        setTimeout(() => {
            frm.remove_custom_button("Opportunity", "Create");
        }, 10);

        // Add your custom Opportunity button
        setTimeout(() => {
            frm.add_custom_button(__("Opportunity"), () => {
                frm.trigger("custom_make_opportunity");
            }, __("Create"));
        }, 50);
    },

    custom_make_opportunity: async function (frm) {
        let fields = [];

        const existing_prospect = (
            await frappe.db.get_value("Prospect Lead", { lead: frm.doc.name }, "name", null, "Prospect")
        ).message?.name;

        if (!existing_prospect) {
            fields.push(
                {
                    label: "Create Prospect",
                    fieldname: "create_prospect",
                    fieldtype: "Check",
                    default: 1,
                },
                {
                    label: "Prospect Name",
                    fieldname: "prospect_name",
                    fieldtype: "Data",
                    default: frm.doc.company_name,
                    depends_on: "create_prospect",
                }
            );
        }

        const existing_contact = (
            await frappe.db.get_value(
                "Contact",
                {
                    first_name: frm.doc.first_name || frm.doc.lead_name,
                    last_name: frm.doc.last_name,
                },
                "name"
            )
        ).message?.name;

        if (!existing_contact) {
            fields.push({
                label: "Create Contact",
                fieldname: "create_contact",
                fieldtype: "Check",
                default: 0,
            });
        }

        if (fields.length > 0) {
            const dialog = new frappe.ui.Dialog({
                title: __("Create Opportunity"),
                fields: fields,
                primary_action_label: __("Create"),
                primary_action() {
                    const data = dialog.get_values();
                    frappe.call({
                        method: "create_prospect_and_contact",
                        doc: frm.doc,
                        args: { data },
                        freeze: true,
                        callback: function (r) {
                            if (!r.exc) {
                                frappe.model.open_mapped_doc({
                                    method: "erpnext.crm.doctype.lead.lead.make_opportunity",
                                    frm: frm,
                                });
                            }
                            dialog.hide();
                        },
                    });
                },
            });
            dialog.show();
        } else {
            frappe.model.open_mapped_doc({
                method: "erpnext.crm.doctype.lead.lead.make_opportunity",
                frm: frm,
            });
        }
    },
});

