function create_psoa_for_customer(frm) {
    const customer_name = frm.doc.name;

    frappe.new_doc("Process Statement Of Accounts").then(() => {
        // cur_frm is now the freshly-created PSOA form
        const new_frm = cur_frm;

        // Pre-fill sensible defaults
        new_frm.doc.company         = frappe.defaults.get_default("company") || "";
        new_frm.doc.posting_date    = frappe.datetime.get_today();
        new_frm.doc.ageing_based_on = "Due Date";

        // Add the customer to the child table (clears any blank placeholder row first)
        new_frm.clear_table("customers");
        new_frm.add_child("customers", { customer: customer_name });

        // Re-render so PSOA's own Client Script logic runs:
        // - hides "Add Row" on customers grid
        // - swaps toolbar to show the Download button
        new_frm.refresh();
    });
}

// Client Script: "Opportunity - Billing Address Management"
// DocType: Opportunity | Apply To: Form | Enabled: yes
// Addresses created from an Opportunity are linked to it and automatically
// become its billing address — no manual selection. (ERPNext v15)
// Fields: custom_customer_billing_address (Link: Address),
