// Registered here (single script), but fires on the Address form.
// Works because navigation Opportunity -> new Address is in-page (SPA),
// so this handler is already loaded.
// Link row is set explicitly (not via frappe.dynamic_link) because core
// opportunity.js overwrites dynamic_link back to the Lead/Customer.
frappe.ui.form.on('Address', {
	refresh(frm) {
		if (!frm.is_new()) return;

		const prev = frappe.get_prev_route(); // ['Form', 'Opportunity', 'CRM-OPP-xxxx']
		if (prev && prev[0] === 'Form' && prev[1] === 'Opportunity' && prev[2]) {
			frm.set_value('links', '');
			frm.add_child('links', {
				link_doctype: 'Opportunity',
				link_name: prev[2],
			});
			frm.refresh_field('links');
			frm.set_value('address_type', 'Billing');
			// standard v15 billing flag; swap for custom_is_billing_address if custom
			frm.set_value('is_primary_address', 1);
		}
	},
});

async function render_billing_address_html(frm) {
	const wrapper = frm.fields_dict.custom_billing_address_html?.$wrapper;
	if (!wrapper) return;
	wrapper.empty();

	if (frm.is_new()) {
		wrapper.html(`<div class="text-muted small">${__('Save the Opportunity to manage addresses')}</div>`);
		return;
	}

	// All addresses linked to this Opportunity, newest first
	const addresses = await frappe.db.get_list('Address', {
		filters: [
			['Dynamic Link', 'link_doctype', '=', 'Opportunity'],
			['Dynamic Link', 'link_name', '=', frm.doc.name],
		],
		fields: ['name', 'address_title', 'address_type', 'address_line1',
			'address_line2', 'city', 'state', 'pincode', 'country'],
		order_by: '`tabAddress`.creation desc',
		limit: 0,
	});

	// Auto-assign: newest linked address is the billing address
	if (addresses.length && frm.doc.custom_customer_billing_address !== addresses[0].name) {
		await assign_billing_address(frm, addresses[0].name);
		if (!frm.is_dirty()) return; // reload_doc re-triggers refresh -> re-render
	}

	const cards = addresses.map((a) => {
		const is_billing = a.name === frm.doc.custom_customer_billing_address;
		const lines = [a.address_line1, a.address_line2,
			[a.city, a.state, a.pincode].filter(Boolean).join(', '), a.country]
			.filter(Boolean).join('<br>');
		return `
			<div class="address-box" style="border:1px solid var(--border-color);
				border-radius:6px;padding:8px 10px;margin-bottom:8px;
				${is_billing ? 'border-color:var(--primary);' : ''}">
				<b>${frappe.utils.escape_html(a.address_title || a.name)}
					(${__(a.address_type)})</b>
				${is_billing ? `<span class="indicator-pill green" style="float:right">${__('Billing')}</span>` : ''}
				<div class="small text-muted" style="margin-top:4px">${lines}</div>
				<div style="margin-top:6px">
					<a class="small" data-action="edit" data-name="${a.name}">${__('Edit')}</a>
				</div>
			</div>`;
	}).join('');

	wrapper.html(`
		${cards || `<div class="text-muted small" style="margin-bottom:8px">${__('No addresses found')}</div>`}
		<button class="btn btn-xs btn-default" data-action="new">
			${__('New Address')}
		</button>
	`);

	wrapper.find('[data-action="new"]').on('click', () => {
		frappe.new_doc('Address', { address_type: 'Billing', is_primary_address: 1 });
	});
	wrapper.find('[data-action="edit"]').on('click', function () {
		frappe.set_route('Form', 'Address', $(this).data('name'));
	});
}

async function assign_billing_address(frm, address_name) {
	// fetch formatted display (same endpoint erpnext.utils.get_address_display uses)
	let { message: display } = await frappe.call({
		method: 'frappe.contacts.doctype.address.address.get_address_display',
		args: { address_dict: address_name },
	});

	// get_address_display returns HTML; if the display field is a plain-text
	// type (Small Text/Data), convert <br> to newlines and strip tags
	const ft = frm.fields_dict.custom_billing_address_display?.df.fieldtype;
	if (display && ft !== 'Text Editor' && ft !== 'HTML Editor') {
		display = display
			.replace(/<br\s*\/?>/gi, '\n')
			.replace(/<[^>]*>/g, '')
			.trim();
	}

	if (frm.is_dirty()) {
		// unsaved edits present: set locally, user saves along with their changes
		frm.set_value('custom_customer_billing_address', address_name);
		frm.set_value('custom_billing_address_display', display || '');
	} else {
		// persist directly without dirtying the form
		await frappe.db.set_value('Opportunity', frm.doc.name, {
			custom_customer_billing_address: address_name,
			custom_billing_address_display: display || '',
		});
		frm.reload_doc();
	}
}

