// Namespace is defined once; re-loading on another form just re-assigns it.
frappe.bizdocs = {
    REQUIRED: ['TL', 'VAT', 'CREDIT_AGREEMENT', 'SIGNED_CONTRACT', 'INSURANCE_CERTIFICATE'],
    OPTIONAL: ['MANAGER_KYC', 'CANCELLED_CHEQUE'],
    ALL_TYPES: ['TL', 'VAT', 'MANAGER_KYC', 'CANCELLED_CHEQUE', 'CREDIT_AGREEMENT', 'SIGNED_CONTRACT', 'INSURANCE_CERTIFICATE', 'Others'],
    EXT: ['pdf', 'jpg', 'jpeg', 'png'],

    can_review() {
        const r = frappe.user_roles || [];
        return r.includes('Sales Manager') || r.includes('System Manager');
    },

    is_allowed_file(url) {
        if (!url) return false;
        const ext = (url.split('?')[0].split('.').pop() || '').toLowerCase();
        return frappe.bizdocs.EXT.includes(ext);
    },

    render(frm) {
        const $wrap = frm.fields_dict.business_docs_html.$wrapper;
        if (frm.is_new()) {
            $wrap.html('<div class="text-muted" style="padding:15px;">Please save this ' +
                frm.doctype + ' first to manage Business Documents.</div>');
            return;
        }
        $wrap.html('<div class="text-muted" style="padding:15px;">Loading documents…</div>');
        frappe.call({
            method: 'business_doc_get_docs',
            args: { reference_doctype: frm.doctype, reference_name: frm.docname },
            callback(r) {
                const data = r.message || { own: [], linked: [] };
                frappe.bizdocs._paint(frm, $wrap, data);
            }
        });
    },

    _status_badge(status) {
        const map = {
            APPROVED: 'green', PENDING_APPROVAL: 'orange',
            REJECTED: 'red', EXPIRED: 'red'
        };
        return `<span class="indicator-pill ${map[status] || 'gray'}">${status || ''}</span>`;
    },

    _expiry_html(expiry) {
        if (!expiry) return '<span class="text-muted">—</span>';
        const today = frappe.datetime.now_date();
        const days = frappe.datetime.get_day_diff(expiry, today);
        let color = '';
        if (days < 0) color = 'color:#c0392b;font-weight:bold;';
        else if (days <= 30) color = 'color:#e67e22;font-weight:bold;';
        return `<span style="${color}">${frappe.datetime.str_to_user(expiry)}</span>`;
    },

    _file_name(url) {
        if (!url) return '(no file)';
        try { return decodeURIComponent(url.split('?')[0].split('/').pop()) || 'file'; }
        catch (e) { return 'file'; }
    },

    _file_html(d) {
        if (!d.attachment) return '—';
        const type = d.document_type ? `<span class="text-muted">${d.document_type}: </span>` : '';
        return `${type}<a href="${d.attachment}" target="_blank">${frappe.utils.escape_html(frappe.bizdocs._file_name(d.attachment))}</a> <span class="text-muted">v${d.current_version || 1}</span>`;
    },

    _checklist(all) {
        // Determine best status per document type across own+linked.
        const by_type = {};
        all.forEach(d => {
            const cur = by_type[d.document_type];
            const rank = { APPROVED: 3, PENDING_APPROVAL: 2, EXPIRED: 1, REJECTED: 1 };
            if (!cur || (rank[d.status] || 0) > (rank[cur] || 0)) by_type[d.document_type] = d.status;
        });
        let pills = '';
        frappe.bizdocs.ALL_TYPES.forEach(t => {
            const required = frappe.bizdocs.REQUIRED.includes(t);
            const st = by_type[t];
            let color, label;
            if (st === 'APPROVED') { color = 'green'; label = 'Approved'; }
            else if (st === 'PENDING_APPROVAL') { color = 'orange'; label = 'Pending'; }
            else if (st === 'EXPIRED') { color = 'red'; label = 'Expired'; }
            else if (st === 'REJECTED') { color = 'red'; label = 'Rejected'; }
            else { color = required ? 'red' : 'gray'; label = 'Missing'; }
            const opt = required ? '' : ' <span class="text-muted">(optional)</span>';
            pills += `<span class="indicator-pill ${color}" style="margin:2px;">${t}: ${label}${opt}</span>`;
        });
        return `<div style="margin-bottom:12px;">${pills}</div>`;
    },

    _own_grid(frm, own) {
        const canReview = frappe.bizdocs.can_review();
        const locked = frm.doc.docstatus === 1;  // submitted -> no new versions
        let rows = '';
        own.forEach(d => {
            let actions = (locked ? '' : `<button class="btn btn-xs btn-default bd-newver" data-name="${d.name}">New Version</button> `) +
                `<button class="btn btn-xs btn-default bd-history" data-name="${d.name}">History</button>`;
            if (canReview && d.status === 'PENDING_APPROVAL') {
                actions += ` <button class="btn btn-xs btn-success bd-approve" data-name="${d.name}">Approve</button>` +
                    ` <button class="btn btn-xs btn-danger bd-reject" data-name="${d.name}">Reject</button>`;
            }
            rows += `<tr>
                <td>${frappe.bizdocs._file_html(d)}</td>
                <td>${frappe.bizdocs._status_badge(d.status)}</td>
                <td>${frappe.bizdocs._expiry_html(d.expiry)}</td>
                <td>${frappe.utils.escape_html(d.uploaded_by || '')}<br><span class="text-muted">${d.upload_date ? frappe.datetime.str_to_user(d.upload_date) : ''}</span></td>
                <td>${actions}</td>
            </tr>`;
        });
        if (!rows) rows = '<tr><td colspan="5" class="text-muted text-center">No documents uploaded on this record yet.</td></tr>';
        return `<h5>Documents on this ${frm.doctype}</h5>
            <table class="table table-bordered" style="font-size:12px;">
            <thead><tr><th>Document</th><th>Status</th><th>Expiry</th><th>Uploaded</th><th>Actions</th></tr></thead>
            <tbody>${rows}</tbody></table>`;
    },

    _linked_grid(linked) {
        if (!linked.length) return '';
        let rows = '';
        linked.forEach(d => {
            const src = `<a href="/app/${frappe.router.slug(d.reference_doctype)}/${encodeURIComponent(d.reference_name)}" target="_blank">${d.reference_doctype}: ${d.reference_name}</a>`;
            rows += `<tr>
                <td>${frappe.bizdocs._file_html(d)}</td>
                <td>${frappe.bizdocs._status_badge(d.status)}</td>
                <td>${frappe.bizdocs._expiry_html(d.expiry)}</td>
                <td>${src}</td>
                <td><button class="btn btn-xs btn-default bd-history" data-name="${d.name}">History</button></td>
            </tr>`;
        });
        return `<h5 style="margin-top:15px;">Linked Documents (from related records)</h5>
            <table class="table table-bordered" style="font-size:12px;">
            <thead><tr><th>Document</th><th>Status</th><th>Expiry</th><th>Source</th><th></th></tr></thead>
            <tbody>${rows}</tbody></table>`;
    },

    _paint(frm, $wrap, data) {
        const own = data.own || [];
        const linked = data.linked || [];
        const all = own.concat(linked);
        const locked = frm.doc.docstatus === 1;  // submitted -> no new uploads / versions
        const top = locked
            ? `<div class="text-muted" style="margin-bottom:10px;padding:6px 10px;background:#f4f5f6;border-radius:4px;">
                 🔒 This ${frm.doctype} is submitted — uploading new documents is locked. Existing documents can still be reviewed.
               </div>`
            : `<div style="margin-bottom:10px;">
                 <button class="btn btn-sm btn-primary bd-upload">+ Upload Document</button>
               </div>`;
        const html = `<div class="bizdocs-root" style="padding:10px;">
            ${top}
            ${frappe.bizdocs._own_grid(frm, own)}
            ${frappe.bizdocs._linked_grid(linked)}
        </div>`;
        $wrap.html(html);

        const $root = $wrap.find('.bizdocs-root');
        $root.find('.bd-upload').on('click', () => frappe.bizdocs.upload_dialog(frm));
        $root.find('.bd-newver').on('click', function () { frappe.bizdocs.newversion_dialog(frm, $(this).data('name')); });
        $root.find('.bd-history').on('click', function () { frappe.bizdocs.history_dialog($(this).data('name')); });
        $root.find('.bd-approve').on('click', function () { frappe.bizdocs.review(frm, $(this).data('name'), 'APPROVED'); });
        $root.find('.bd-reject').on('click', function () { frappe.bizdocs.review(frm, $(this).data('name'), 'REJECTED'); });
    },

    upload_dialog(frm) {
        const d = new frappe.ui.Dialog({
            title: 'Upload Document',
            fields: [
                { fieldname: 'document_type', label: 'Document Type', fieldtype: 'Select', options: frappe.bizdocs.ALL_TYPES.concat(['Others']), reqd: 1 },
                { fieldname: 'document_number', label: 'Document Number', fieldtype: 'Data', reqd: 1 },
                { fieldname: 'attachment', label: 'Document', fieldtype: 'Attach', reqd: 1 },
                { fieldname: 'expiry', label: 'Expiry', fieldtype: 'Date', reqd: 1 },
            ],
            primary_action_label: 'Upload',
            primary_action(v) {
                if (!frappe.bizdocs.is_allowed_file(v.attachment)) {
                    frappe.msgprint('Only PDF, JPG, JPEG or PNG files are allowed.');
                    return;
                }
                const now = frappe.datetime.now_datetime();
                frappe.call({
                    method: 'frappe.client.insert',
                    args: {
                        doc: {
                            doctype: 'Business Documentation',
                            reference_doctype: frm.doctype,
                            reference_name: frm.docname,
                            document_type: v.document_type,
                            document_number: v.document_number,
                            attachment: v.attachment,
                            expiry: v.expiry,
                            status: 'PENDING_APPROVAL',
                            uploaded_by: frappe.session.user,
                            upload_date: now,
                            current_version: 1,
                            versions: [{
                                version_no: 1, attachment: v.attachment,
                                uploaded_by: frappe.session.user, upload_date: now,
                                change_note: 'Initial upload'
                            }]
                        }
                    },
                    callback() {
                        frappe.show_alert({ message: 'Document uploaded', indicator: 'green' });
                        d.hide();
                        frappe.bizdocs.render(frm);
                    }
                });
            }
        });
        d.show();
    },

    newversion_dialog(frm, tracker) {
        const d = new frappe.ui.Dialog({
            title: 'Upload New Version',
            fields: [
                { fieldname: 'attachment', label: 'New File', fieldtype: 'Attach', reqd: 1 },
                { fieldname: 'note', label: 'Change Note', fieldtype: 'Small Text' },
            ],
            primary_action_label: 'Upload Version',
            primary_action(v) {
                if (!frappe.bizdocs.is_allowed_file(v.attachment)) {
                    frappe.msgprint('Only PDF, JPG, JPEG or PNG files are allowed.');
                    return;
                }
                frappe.call({
                    method: 'business_doc_add_version',
                    args: { tracker: tracker, file_url: v.attachment, note: v.note || '' },
                    callback(r) {
                        frappe.show_alert({ message: 'New version v' + (r.message && r.message.current_version) + ' added', indicator: 'green' });
                        d.hide();
                        frappe.bizdocs.render(frm);
                    }
                });
            }
        });
        d.show();
    },

    history_dialog(tracker) {
        frappe.call({
            method: 'frappe.client.get',
            args: { doctype: 'Business Documentation', name: tracker },
            callback(r) {
                const doc = r.message;
                let rows = '';
                (doc.versions || []).slice().sort((a, b) => b.version_no - a.version_no).forEach(v => {
                    rows += `<tr><td>v${v.version_no}</td>
                        <td><a href="${v.attachment}" target="_blank">file</a></td>
                        <td>${frappe.utils.escape_html(v.uploaded_by || '')}</td>
                        <td>${v.upload_date ? frappe.datetime.str_to_user(v.upload_date) : ''}</td>
                        <td>${frappe.utils.escape_html(v.change_note || '')}</td></tr>`;
                });
                const review = `<p><b>Current status:</b> ${doc.status}<br>
                    <b>Reviewed by:</b> ${doc.reviewed_by || '—'}
                    ${doc.reviewed_on ? '(' + frappe.datetime.str_to_user(doc.reviewed_on) + ')' : ''}</p>`;
                const d = new frappe.ui.Dialog({ title: 'History — ' + tracker, size: 'large' });
                $(d.body).html(`${review}
                    <table class="table table-bordered" style="font-size:12px;">
                    <thead><tr><th>Version</th><th>File</th><th>Uploaded By</th><th>Date</th><th>Note</th></tr></thead>
                    <tbody>${rows || '<tr><td colspan="5" class="text-muted">No versions.</td></tr>'}</tbody></table>`);
                d.show();
            }
        });
    },

    review(frm, tracker, status) {
        frappe.confirm(`Set this document to ${status}?`, () => {
            frappe.call({
                method: 'frappe.client.set_value',
                args: {
                    doctype: 'Business Documentation', name: tracker,
                    fieldname: {
                        status: status,
                        reviewed_by: frappe.session.user,
                        reviewed_on: frappe.datetime.now_datetime()
                    }
                },
                callback() {
                    frappe.show_alert({ message: 'Document ' + status, indicator: status === 'APPROVED' ? 'green' : 'red' });
                    frappe.bizdocs.render(frm);
                }
            });
        });
    }
};

