    },

    _checklist(all) {
        // Determine best status per document type across own+linked.
        const by_type = {};
        all.forEach(d => {
            const cur = by_type[d.document_type];
            const rank = { APPROVED: 3, PENDING_APPROVAL: 2, EXPIRED: 1, REJECTED: 1 };
            if (!cur || (rank[d.status] || 0) > (rank[cur] || 0)) by_type[d.document_type] = d.status;
        });
        let pills = '';
        frappe.bizdocs.ALL_TYPES.forEach(t => {
            const required = frappe.bizdocs.REQUIRED.includes(t);
            const st = by_type[t];
            let color, label;
            if (st === 'APPROVED') { color = 'green'; label = 'Approved'; }
            else if (st === 'PENDING_APPROVAL') { color = 'orange'; label = 'Pending'; }
            else if (st === 'EXPIRED') { color = 'red'; label = 'Expired'; }
            else if (st === 'REJECTED') { color = 'red'; label = 'Rejected'; }
            else { color = required ? 'red' : 'gray'; label = 'Missing'; }
            const opt = required ? '' : ' <span class="text-muted">(optional)</span>';
            pills += `<span class="indicator-pill ${color}" style="margin:2px;">${t}: ${label}${opt}</span>`;
